      { type: "video", title: "video linfoma de Hodgkin esclerosis nodular", date: "Publicado: 26 may 2023", url: "https://pathpresenter.net/public/display?token=2e61c3f7", definicion: ["El linfoma de Hodgkin es un tipo de cáncer que afecta el sistema linfático", "La esclerosis nodular es un subtipo de linfoma de Hodgkin caracterizado por la formación de nódulos de tejido fibroso", "Se presenta con mayor frecuencia en adultos jóvenes y tiene un pronóstico generalmente favorable con tratamiento"], caracteristicas: ["Presencia de células de Reed-Sternberg, que son células anormales grandes y binucleadas", "Infiltración de células inflamatorias como linfocitos, eosinófilos y histiocitos en el tejido linfático", "Formación de nódulos de tejido fibroso que rodean a las células neoplásicas", "Arquitectura nodular con áreas de esclerosis fibrosa que pueden rodear a los nódulos tumorales"] },
      { type: "video", title: "VIDEO OSTEOSARCOMA", date: "Publicado: 25 may 2023", url: "https://pathpresenter.net/public/display?token=a4ebb307", definicion: ["Es un tipo de cáncer que se origina en los huesos", "Se caracteriza por la producción de matriz ósea anormal por parte de las células cancerosas", "Es el tipo más común de sarcoma óseo y puede ocurrir en cualquier hueso, pero es más frecuente en los huesos largos de las extremidades"], caracteristicas: ["Células tumorales con núcleos pleomórficos y anisocariosis", "Producción de matriz ósea anormal, que puede ser osteoide, condroide o fibroide", "Presencia de células gigantes y mitosis atípicas", "Invasión destructiva del hueso circundante y posible extensión a los tejidos blandos adyacentes"] },
      { type: "book", title: "OSTEOSARCOMA 2", date: "Publicado: 22 may 2023", url: "https://pathpresenter.net/public/display?token=a4ebb307", definicion: ["Es un tipo de cáncer que se origina en los osteoblastos, las células que producen el tejido óseo", "Se caracteriza por la producción de matriz ósea anormal por parte de las células tumorales", "Es el tipo más común de sarcoma óseo y puede ocurrir en cualquier edad, pero es más frecuente en adolescentes y adultos jóvenes"], caracteristicas: ["Presenta células tumorales con núcleos pleomórficos y anisocariosis, con áreas de necrosis y hemorragia", "Se observan trabéculas óseas anormales y desorganizadas, con osteoides producidos por las células tumorales", "Puede haber áreas de cartilago y tejido fibroso dentro del tumor", "La inmunohistoquímica puede mostrar positividad para marcadores como vimentina, osteocalcina y osteopontina"] },
      { type: "book", title: "OSTEOSARCOMA", date: "Publicado: 22 may 2023", url: "https://pathpresenter.net/public/display?token=a4ebb307", definicion: ["Es un tipo de cáncer que se origina en los osteoblastos, las células que producen el tejido óseo", "Se caracteriza por la producción de matriz ósea anormal por parte de las células tumorales", "Es el tipo más común de sarcoma óseo y puede afectar a personas de cualquier edad, aunque es más frecuente en adolescentes y adultos jóvenes"], caracteristicas: ["Presenta células tumorales con núcleos pleomórficos y anisocariosis, lo que indica un alto grado de anaplasia", "Se observan áreas de necrosis y hemorragia dentro del tumor", "La producción de matriz ósea anormal puede ser osteoide, condroide o fibroide", "Puede mostrar invasión a los tejidos blandos circundantes y metástasis a distancia, especialmente a los pulmones"] },
      { type: "book", title: "LINFOMA DE HODGKIN", date: "Editado: 2 abr 2023", url: "https://pathpresenter.net/public/display?token=2e61c3f7", definicion: ["El linfoma de Hodgkin es un tipo de cáncer que afecta el sistema linfático", "Se caracteriza por la presencia de células de Reed-Sternberg, que son células anormales que se encuentran en los ganglios linfáticos", "Es una de las formas más comunes de linfoma y puede afectar a personas de cualquier edad"], caracteristicas: ["La presencia de células de Reed-Sternberg es característica del linfoma de Hodgkin", "Las células de Reed-Sternberg pueden ser binucleadas o multinucleadas y tienen un aspecto peculiar", "El linfoma de Hodgkin puede afectar cualquier parte del sistema linfático, incluyendo los ganglios linfáticos, el bazo y la médula ósea", "La enfermedad puede ser clasificada en diferentes subtipos según la presencia de ciertas características histológicas"] },
      { type: "book", title: "LINFOMA DE HODGKIN ESCLEROSIS NODULAR 2", date: "Editado: 2 abr 2023", url: "https://pathpresenter.net/public/display?token=609b03ce", definicion: ["El linfoma de Hodgkin esclerosi nodular es un tipo de linfoma de Hodgkin caracterizado por la presencia de esclerosis (endurecimiento) en los ganglios linfáticos", "Se caracteriza por la formación de nódulos de tejido cicatricial dentro de los ganglios linfáticos", "Es una de las formas más comunes de linfoma de Hodgkin y se presenta con mayor frecuencia en adultos jóvenes"], caracteristicas: ["La presencia de células de Reed-Sternberg lacunares, que son células grandes y anormales con múltiples núcleos", "La formación de nódulos de tejido cicatricial (esclerosis) dentro de los ganglios linfáticos", "La infiltración de células inflamatorias, como linfocitos y eosinófilos, en el tejido linfático", "La presencia de fibrosis (tejido cicatricial) que puede rodear y separar los nódulos de tejido linfático"] },
      { type: "book", title: "HODKING ESCLEROSIS NODULAR VARIANTE SINCITIAL40X", date: "Editado: 2 abr 2023", url: "https://pathpresenter.net/public/display?token=0b80454e", definicion: ["La enfermedad de Hodgkin es un tipo de linfoma que afecta el sistema inmunológico", "La variante sincitial de la esclerosis nodular es una forma rara y agresiva de la enfermedad de Hodgkin", "Se caracteriza por la presencia de células de Reed-Sternberg en un contexto de inflamación y fibrosis"], caracteristicas: ["Presencia de células de Reed-Sternberg con morfología sincicial", "Infiltrado inflamatorio mixto con linfocitos, histiocitos y eosinófilos", "Fibrosis lacunar y esclerosis nodular con formación de nódulos", "Expansión sinusal y arquitectura nodular con áreas de necrosis y hemorragia"] }
