      { type: "book", title: "CARCINOMA GASTRICO", date: "Editado: 2 abr 2023", url: "https://pathpresenter.net/public/display?token=479c2163", definicion: ["El carcinoma gástrico es un tipo de cáncer que se origina en el estómago", "Se desarrolla a partir de las células epiteliales que recubren el interior del estómago", "Puede ser causado por factores genéticos, infecciones como la de Helicobacter pylori y factores dietéticos"], caracteristicas: ["Células cancerosas con núcleos irregulares y pleomorfismo nuclear", "Invasión de las células cancerosas en la pared del estómago", "Formación de estructuras glandulares anormales o crecimiento en masa", "Presencia de metástasis en ganglios linfáticos o en otros órganos"] },
      { type: "book", title: "ADENOCARCINOMA GASTRICO", date: "Editado: 2 abr 2023", url: "https://pathpresenter.net/public/display?token=36aff2a7", definicion: ["El adenocarcinoma gástrico es un tipo de cáncer que se origina en el revestimiento del estómago", "Se caracteriza por el crecimiento anormal de células glandulares que invaden el tejido estomacal", "Es uno de los cánceres más comunes en todo el mundo, con una mayor incidencia en países asiáticos"], caracteristicas: ["Presencia de células cancerosas con características glandulares, como la formación de glándulas anormales", "Invasión del tejido estomacal por parte de las células cancerosas, lo que puede llevar a la formación de úlceras", "Pérdida de la arquitectura glandular normal del estómago, reemplazada por un patrón desorganizado de crecimiento", "Posibilidad de metástasis a ganglios linfáticos y otros órganos, como el hígado y los pulmones"] },
      { type: "book", title: "CARCINOMA EPIDERMOIDE 2", date: "Editado: 2 abr 2023", url: "https://pathpresenter.net/public/display?token=fec9c6e4", definicion: ["El carcinoma epidermoide es un tipo de cáncer que se origina en las células epiteliales de la piel", "Se caracteriza por la proliferación anormal de células epiteliales que invaden los tejidos circundantes", "Es uno de los tipos más comunes de cáncer de piel y puede aparecer en cualquier parte del cuerpo"], caracteristicas: ["Presencia de células atípicas con núcleos hiperkromáticos y pleomórficos", "Formación de estructuras similares a islotes o cordones de células epiteliales anormales", "Invasión de las células tumorales en la dermis y posiblemente en tejidos más profundos", "Posible presencia de cuerpos de inclusión de queratina y otros cambios degenerativos en las células tumorales"] },
      { type: "book", title: "CARCINOMA EPIDERMOIDE 1", date: "Editado: 2 abr 2023", url: "https://pathpresenter.net/public/display?token=25e9c3f7", definicion: ["El carcinoma epidermoide es un tipo de cáncer que se origina en las células epiteliales de la piel", "Se caracteriza por la proliferación anormal de células epiteliales que invaden los tejidos circundantes", "Puede ocurrir en cualquier parte del cuerpo, pero es más común en áreas expuestas al sol como la cara, el cuello y las manos"], caracteristicas: ["Presencia de células atípicas con núcleos hiperkromáticos y pleomórficos", "Formación de estructuras epiteliales anormales como brotes y cordones", "Invasión de las células tumorales en la dermis y otros tejidos subyacentes", "Posible presencia de cuerpos de inclusión de keratina y otros cambios degenerativos"] },
      { type: "book", title: "CARCINOMA ESCAMOSO EN LENGUA", date: "Editado: 2 abr 2023", url: "https://pathpresenter.net/public/display?token=102af0cc", definicion: ["El carcinoma escamoso en lengua es un tipo de cáncer que se desarrolla en la lengua", "Se origina en las células escamosas que recubren la superficie de la lengua", "Es uno de los tipos más comunes de cáncer de cabeza y cuello"], caracteristicas: ["Presencia de células anaplásicas con núcleos irregulares y aumento de la relación núcleo-citoplasma", "Invasión de las células cancerosas en la estroma subyacente", "Formación de estructuras similares a islotes o cordones de células cancerosas", "Presencia de queratinización, que se manifiesta como la formación de perlitas de queratina o cuerpos de keratinización"] },
      { type: "book", title: "CARCINOMA DUCTAL DE MAMA", date: "Editado: 2 abr 2023", url: "https://pathpresenter.net/public/display?token=06e2fb28", definicion: ["Es el tipo más común de cáncer de mama, originándose en los conductos mamarios.", "Se caracteriza por el crecimiento anormal de células epiteliales en los ductos mamarios.", "Puede ser invasivo o no invasivo, dependiendo de si ha penetrado la pared del ducto o no."], caracteristicas: ["Células tumorales que forman estructuras ductales anormales.", "Proliferación celular desorganizada con pérdida de polaridad.", "Presencia de atipia nuclear, como núcleos grandes y pleomórficos.", "Invasión del estroma mamario circundante por parte de las células tumorales."] },
      { type: "book", title: "CARCINOMA DUCTAL 40X", date: "Editado: 2 abr 2023", url: "https://pathpresenter.net/public/display?token=917cceca", definicion: ["El carcinoma ductal es un tipo de cáncer que se origina en los conductos mamarios", "Se caracteriza por el crecimiento anormal de células en los conductos mamarios", "Puede ser in situ, es decir, no invasivo, o invasivo, cuando se extiende más allá de los conductos"], caracteristicas: ["Células neoplásicas que forman estructuras ductales anormales", "Proliferación celular desorganizada con pérdida de polaridad", "Presencia de atipia nuclear y citoplasmática", "Invasión del estroma mamario circundante en casos de carcinoma ductal invasivo"] }
