      { type: "book", title: "LEIOMIOMA 1", date: "Editado: 2 abr 2023", url: "https://pathpresenter.net/public/display?token=45ed22f5", definicion: ["Tumor benigno que se desarrolla en el músculo liso del útero", "Puede causar síntomas como dolor pélvico, sangrado menstrual abundante y presión sobre la vejiga", "Es una de las afecciones ginecológicas más comunes en mujeres en edad reproductiva"], caracteristicas: ["Está compuesto por células musculares lisas que se han proliferado de manera anormal", "Presenta un patrón de crecimiento bien definido, con células dispuestas en haces o fascículos", "Las células tumorales suelen ser uniformes y no presentan signos de malignidad", "Puede mostrar áreas de degeneración, como necrosis, hemorragia o calcificación, especialmente en leiomiomas grandes"] },
      { type: "book", title: "LEIOMIOMA 2", date: "Editado: 2 abr 2023", url: "https://pathpresenter.net/public/display?token=10f4c5b9", definicion: ["Tumor benigno que se desarrolla en el músculo liso del útero", "Puede causar síntomas como dolor pélvico, sangrado menstrual abundante y presión sobre la vejiga", "Es una de las afecciones ginecológicas más comunes en mujeres en edad reproductiva"], caracteristicas: ["Está compuesto por células musculares lisas que se han proliferado de manera descontrolada", "Presenta un patrón de crecimiento bien definido, con células dispuestas en haces o fascículos", "Las células tumorales suelen ser uniformes y no presentan signos de atipia o malignidad", "Puede tener diferentes tamaños y ubicaciones dentro del útero, incluyendo el miometrio y la submucosa"] }
