      { type: "book", title: "SJOGREN", date: "Editado: 2 abr 2023", url: "https://pathpresenter.net/public/display?token=5af328c0", definicion: ["Enfermedad autoinmune crónica que afecta principalmente las glándulas salivales y lacrimales", "Se caracteriza por la inflamación y destrucción de las glándulas exocrinas, lo que lleva a síntomas de sequedad en la boca y los ojos", "Puede presentarse de forma aislada (Sjögren primario) o en asociación con otras enfermedades autoinmunes, como el lupus eritematoso sistémico o la artritis reumatoide"], caracteristicas: ["Infiltración linfocítica focal en las glándulas salivales y lacrimales, con formación de focos linfocíticos", "Destrucción de los acinos glandulares y su reemplazo por tejido conjuntivo", "Presencia de cuerpos de Russell y cuerpos de colágeno en las glándulas afectadas", "Inflamación y fibrosis en las glándulas salivales y lacrimales, lo que lleva a una disminución en la producción de saliva y lágrimas"] },
      { type: "book", title: "NEUMONIA INTERSTICIAL", date: "Editado: 2 abr 2023", url: "https://pathpresenter.net/public/display?token=ac3a2996", definicion: ["La neumonía intersticial es una inflamación del tejido intersticial del pulmón", "Se caracteriza por la inflamación de los espacios intersticiales del pulmón, incluyendo el tejido conectivo y el espacio alveolar", "Puede ser causada por una variedad de factores, incluyendo infecciones, enfermedades autoinmunes y exposición a toxinas"], caracteristicas: ["Infiltración de células inflamatorias en el tejido intersticial", "Fibrosis y cicatrización del tejido pulmonar", "Presencia de células gigantes y granulomas en algunos casos", "Alteraciones en la arquitectura alveolar y el intercambio gaseoso"] },
      { type: "book", title: "PENFIGO VULGAR 1", date: "Editado: 2 abr 2023", url: "https://pathpresenter.net/public/display?token=81215d1d", definicion: ["Enfermedad autoinmune crónica que afecta la piel y las mucosas", "Se caracteriza por la formación de ampollas y erosiones en la piel y las mucosas", "Puede ser grave y potencialmente mortal si no se trata adecuadamente"], caracteristicas: ["Presencia de acantólisis, que es la separación de las células epiteliales", "Formación de ampollas intraepiteliales y subepiteliales", "Infiltrado inflamatorio en la dermis y la epidermis", "Depósitos de inmunoglobulinas y complemento en la unión dermo-epidérmica"] },
      { type: "book", title: "PENFIGO VULGAR 2", date: "Editado: 2 abr 2023", url: "https://pathpresenter.net/public/display?token=89dea610", definicion: ["Enfermedad autoinmune crónica que afecta la piel y las mucosas", "Se caracteriza por la formación de ampollas y erosiones en la piel y las mucosas", "Puede ser grave y potencialmente mortal si no se trata adecuadamente"], caracteristicas: ["Presencia de anticuerpos contra las desmogleínas, proteínas que mantienen unidas las células epiteliales", "Ampollas intraepiteliales que se forman debido a la separación de las células epiteliales", "Infiltrado inflamatorio en la dermis y la epidermis", "Acantólisis, que es la separación y muerte de las células epiteliales debido a la acción de los anticuerpos"] }
