      { type: "book", title: "ULCERA TIFICA", date: "Publicado: 2 abr 2023", url: "https://pathpresenter.net/public/display?token=2ad6b0e2", definicion: ["La úlcera tífica es una complicación grave de la fiebre tifoidea", "Se caracteriza por la formación de úlceras en el intestino delgado", "Puede ser causada por la bacteria Salmonella Typhi"], caracteristicas: ["La úlcera tífica presenta una lesión ovalada o redondeada en la mucosa intestinal", "La lesión puede tener un diámetro de hasta 1 cm y una profundidad que puede llegar a la muscularis mucosae", "El borde de la úlcera puede ser elevado y la base puede estar cubierta de una capa de fibrina y células inflamatorias", "La histopatología puede mostrar una infiltración de células inflamatorias, como neutrófilos y linfocitos, en la pared intestinal"] },
      { type: "book", title: "VASCULITIS", date: "Publicado: 2 abr 2023", url: "https://pathpresenter.net/public/display?token=017c9aa6", definicion: ["La vasculitis es una inflamación de los vasos sanguíneos", "Puede afectar arterias, venas o capilares", "Se caracteriza por la inflamación y daño a la pared vascular"], caracteristicas: ["Inflamación de la pared vascular con infiltración de células inflamatorias", "Daño a la pared vascular con necrosis y desintegración de la lámina basal", "Aumento de la permeabilidad vascular con extravasación de fluidos y células", "Formación de trombos y oclusión vascular en algunos casos"] },
      { type: "book", title: "PIELONEFRITIS CRONICA", date: "Editado: 4 abr 2023", url: "https://pathpresenter.net/public/display?token=9cbecd92", definicion: ["Infección bacteriana crónica del riñón", "Inflamación del parénquima renal y el sistema colector", "Puede ser causada por bacterias como Escherichia coli"], caracteristicas: ["Presencia de infiltrados inflamatorios crónicos en el riñón", "Fibrosis y cicatrices en el tejido renal", "Atrofia de los túbulos renales y glomérulos", "Presencia de cálculos renales o litiasis en algunos casos"] }
